import React from "react";
import { createRoot } from "react-dom/client";
import {
  AlertTriangle, Binoculars, BookOpen, Castle, CheckCircle2, ChevronRight, CircleDollarSign,
  CirclePlay, Clock3, Crown, Dumbbell, Eye, FilePenLine, Gavel, Landmark, ListChecks,
  LockKeyhole, LogOut, MapPinned, MessageSquareText, MessagesSquare, PackageOpen, RotateCcw,
  Route, Save, ScrollText, Search, SearchCheck, Settings, Shield, ShieldCheck, Stamp, Swords,
  Trash2, TrendingDown, TrendingUp, Undo2, UserRoundPlus, Users, Wheat, X,
} from "lucide-react";
import "./styles.css";
import "./army.css";
import "./situations.css";
import "./reports.css";
import "./generated-backgrounds.css";
import WorldMap from "./WorldMap";

type Tab = "court" | "overview" | "map" | "army" | "memorials" | "policy" | "history";
type Order = "hold" | "verify" | "reconcile" | "constrain" | "prepare_retreat" | "sally";
type DirectiveKind = "relief" | "tax" | "supply" | "mobilize" | "fortify" | "investigate" | "appoint" | "mediate";
type CoreState = any;
type Management = {
  turn: number;
  finance: { cash: number; grain: number; monthly_income: number; monthly_expenses: number; monthly_grain: number };
  regions: Record<string, { name: string; support: number; unrest: number; tax_rate: number; fortification: number }>;
  armies: Record<string, { name: string; region: string; strength: number; fit_strength: number; supply: number; morale: number }>;
  issues: Record<string, { title: string; tension: number; progress: number; status: string; assignee: string }>;
  characters: Record<string, { name: string; office: string; loyalty: number; ability: number; status: string }>;
  directives: Array<{ id: number; kind: DirectiveKind; target: string; amount: number; subject: string }>;
};
type Catalog = { regions: any[]; armies: any[]; characters: any[]; initial_finance: any; ongoing_issues: any[]; acts: any[]; evidence_legend: Record<string, string> };
type Snapshot = { state: CoreState; management: Management; catalog: Catalog; acts: any[]; progress: any; runtime: Record<string,any>; conversation:any; strategy:any; agent_runs:any[]; save_slots:any[] };

const nav: Array<{ id: Tab; label: string; Icon: typeof Shield }> = [
  { id: "court", label: "朝堂", Icon: Users }, { id: "overview", label: "军情", Icon: Shield }, { id: "map", label: "天下", Icon: MapPinned },
  { id: "army", label: "诸军", Icon: Swords },
  { id: "memorials", label: "奏报", Icon: FilePenLine },
  { id: "policy", label: "国策", Icon: Landmark },
  { id: "history", label: "史册", Icon: BookOpen },
];
const orders: Array<{ id: Order; title: string; note: string; gain: string; risk: string; Icon: typeof Shield }> = [
  { id: "hold", title: "闭关固守", note: "耗时一旬", gain: "稳军心、固营垒", risk: "皇威受损", Icon: ShieldCheck }, { id: "verify", title: "三路复核", note: "耗时三日", gain: "提高情报置信", risk: "贻误战机", Icon: SearchCheck },
  { id: "reconcile", title: "召对释疑", note: "耗时一日", gain: "统一军令", risk: "朝争加剧", Icon: MessagesSquare }, { id: "constrain", title: "更易监军", note: "耗时三日", gain: "压低谣报", risk: "将帅不满", Icon: ListChecks },
  { id: "prepare_retreat", title: "整备退路", note: "耗时五日", gain: "防止溃退级联", risk: "士气波动", Icon: Undo2 }, { id: "sally", title: "奉诏出击", note: "立即决战", gain: "结算灵宝战局", risk: "准备不足则大溃", Icon: Swords },
];
const directiveMeta: Record<DirectiveKind, { label: string; domain: "regions" | "armies" | "issues" | "characters" }> = {
  relief: { label: "开仓赈济", domain: "regions" }, tax: { label: "加征赋税", domain: "regions" },
  supply: { label: "转运军粮", domain: "armies" }, mobilize: { label: "征发兵员", domain: "armies" },
  fortify: { label: "修筑城防", domain: "regions" }, investigate: { label: "查明情形", domain: "issues" },
  appoint: { label: "授官任职", domain: "characters" }, mediate: { label: "调停争端", domain: "issues" },
};
const evidenceLabel: Record<string, string> = { documented: "史实锚定", disputed: "史料争议", estimate: "制作估算", design_estimate: "虚构设计" };
const attributeLabel: Record<string,string>={military:"统兵",administration:"治政",politics:"权术",diplomacy:"交涉",loyalty:"忠诚",integrity:"操守"};
const powerLabel: Record<string,string>={tang_xuanzong:"玄宗朝廷",tang_suzong:"肃宗朝廷",yan_an:"安氏燕廷",yan_shi:"史氏燕廷",uighur:"回纥",tibet:"吐蕃",contested:"争夺中"};
const statusLabel: Record<string,string>={capital_under_threat:"京师告急",fortified_front:"坚城前线",ambush_corridor:"伏击狭道",yan_forward_base:"燕军前进基地",yan_capital:"燕廷都城",yan_home_base:"燕军根本",split_control:"分裂控制",loyal_military_base:"忠唐军镇",western_garrison:"西陲军镇",tibetan_frontier:"吐蕃边境",fallback_capital_candidate:"行在候选",imperial_escape_route:"皇驾西行路线",occupied_resistance:"敌后抵抗",loyal_resistance:"忠唐抵抗",jianghuai_gateway:"江淮门户",canal_revenue_hub:"漕运财赋枢纽",defending:"据守",active_campaign:"出征中",ambush_prepared:"设伏待敌",strategic_reserve:"战略预备",hebei_campaign:"河北作战",asset:"资产",grain_asset:"粮食资产",receivable:"待解收入",liability:"支出承诺",restricted_asset:"专用储备",corroborated:"已互证",contradicted:"已反证",unverified:"待核"};
const cn=(value:string)=>statusLabel[value]||powerLabel[value]||value;

function Metric({ label, value, unit = "" }: { label: string; value: number | string; unit?: string }) {
  return <div className="metric"><span>{label}</span><strong>{typeof value === "number" ? value.toLocaleString() : value}</strong><small>{unit}</small></div>;
}
function Meter({ value, danger = false }: { value: number; danger?: boolean }) {
  return <span className={`mini-meter ${danger ? "danger" : ""}`}><i style={{ width: `${Math.max(0, Math.min(100, value))}%` }}/></span>;
}
function Evidence({ value }: { value: string }) { return <span className={`evidence ${value}`}>{evidenceLabel[value] || value}</span>; }
function Portrait({ character, large = false }: { character:any; large?:boolean }) {
  const [failed,setFailed]=React.useState(false);
  return failed ? <span className={large ? "large-seal" : "portrait-seal"}>{character.name.slice(-1)}</span> : <img className={large ? "portrait-image large" : "portrait-image"} src={`/assets/portraits/${character.id}.webp`} alt={character.name} onError={()=>setFailed(true)}/>;
}

function CampaignMap({ data, management, strategy, selected, onSelect }: { data: Catalog; management: Management; strategy?: any; selected?: string; onSelect?: (id: string) => void }) {
  const armies=Object.values(strategy?.armies||{}) as any[];
  return <div className="terrain-map" role="img" aria-label="安史之乱天下形势图">
    <img src="/assets/backgrounds/tang-terrain.webp" alt="唐代天下地形底图"/>
    <div className="map-wash tang"/><div className="map-wash yan"/>
    {data.regions.map(region=>{const runtime=management.regions[region.id];const controller=region.controller.startsWith("yan")?"yan":region.controller==="contested"?"contested":"tang";return <button key={region.id} className={`terrain-point ${controller} ${selected===region.id?"selected":""}`} style={{left:`${region.map.x}%`,top:`${region.map.y}%`}} onClick={()=>onSelect?.(region.id)} title={`${region.name} · ${cn(region.controller)}`}><i/><b>{region.name.split("·")[0]}</b><small>民心 {runtime?.support??"-"} · 动乱 {runtime?.unrest??"-"}</small></button>})}
    {armies.map((army:any)=>{const region=data.regions.find(item=>item.id===army.region);if(!region)return null;const hostile=String(army.power).startsWith("yan");return <span className={`map-standard ${hostile?"yan":"tang"}`} key={army.id} style={{left:`${region.map.x+2}%`,top:`${region.map.y-7}%`}} title={`${army.name} · ${Number(army.strength).toLocaleString()}人`}>{hostile?"燕":"唐"}</span>})}
    <div className="terrain-legend"><span><i className="tang"/>唐军控制</span><span><i className="yan"/>燕军控制</span><span><i className="contested"/>争夺地区</span></div>
  </div>
}

function SectionHead({ eyebrow, title, extra }: { eyebrow: string; title: string; extra?: React.ReactNode }) {
  return <div className="section-head"><div><span>{eyebrow}</span><h2>{title}</h2></div>{extra}</div>;
}

function ObjectivePanel({snap}:{snap:Snapshot}){const objectives=[
  ["三回合内稳住潼关军令",snap.progress.total_turn<=3?"进行中":"期限已过"],
  ["查明前线军报真伪",snap.management.issues?.tongguan_intelligence?.progress>=50?"已推进":"待推进"],
  ["维持中央粮储不少于五百",snap.management.finance.grain>=500?"达成":"告急"],
];return <aside className="objective-panel"><header><span>短期任务</span><b>天宝十五载 · 潼关危局</b></header>{objectives.map(([title,status],index)=><article key={title}><em>0{index+1}</em><div><b>{title}</b><small>{status}</small></div></article>)}</aside>}

function SituationPanel({snap}:{snap:Snapshot}){const situations=snap.progress.situations||[];const modifiers=snap.progress.modifiers||[];return <section className="situation-panel"><header><div><span>国势仪表</span><h2>局势进度</h2></div><small>每回合由推演模型综合判断</small></header><div className="situation-list">{situations.map((item:any)=><article key={item.id}><div className="situation-title"><b>{item.title}</b><span className={item.trend==="恶化"?"down":item.trend==="向好"?"up":""}>{item.trend==="向好"?<TrendingUp size={13}/>:item.trend==="恶化"?<TrendingDown size={13}/>:<Clock3 size={13}/>} {item.status}</span></div><p>{item.summary}</p><div className="situation-meter"><i className={item.status==="已崩坏"?"failed":item.status==="已完成"?"complete":""} style={{width:String(item.progress)+"%"}}/></div><small>{item.progress}/100 · {item.last_reason}</small></article>)}</div>{modifiers.length>0&&<div className="modifier-strip"><b>帝国修正</b>{modifiers.slice(-5).map((item:any)=><span key={item.id+"-"+item.applied_turn} title={item.description}>{item.name}</span>)}</div>}</section>}

function Overview({ snap, onOrder, orderBusy, report }: { snap: Snapshot; onOrder: (order: Order) => void; orderBusy: boolean; report:any }) {
  const { state, management, catalog: fullCatalog } = snap; const frontlineIds=new Set(["changan","tongguan","lingbao","shanjun","luoyang","hedong","shuofang","fanyang","changshan","pingyuan","suiyang"]); const catalog={...fullCatalog,regions:fullCatalog.regions.filter((region:any)=>frontlineIds.has(region.id))};
  return <><SituationPanel snap={snap}/><ObjectivePanel snap={snap}/><div className="overview-grid">
    <section className="map-panel"><SectionHead eyebrow="天下形势" title="关中与河北战局" extra={<b>{Object.keys(management.armies).length} 支军队在册</b>}/><CampaignMap data={catalog} management={management} strategy={snap.strategy}/></section>
    <aside className="issues-panel"><SectionHead eyebrow="御前急务" title="待决事项" extra={<AlertTriangle size={18}/>}/>
      {Object.entries(management.issues).slice(0, 6).map(([id, issue]) => <div className="issue-row" key={id}><div><b>{issue.title}</b><span>{issue.assignee ? `承办：${management.characters[issue.assignee]?.name || issue.assignee}` : "尚未责成"}</span></div><strong>{issue.tension}</strong><Meter value={issue.tension} danger/></div>)}
    </aside>
    <section className="intel-panel"><SectionHead eyebrow="御史台与军报" title="已知情报" extra={<Eye size={18}/>}/>
      {state.intel_claims.slice(0, 4).map((claim: any) => <article key={claim.id}><div><b>{claim.source}</b><strong>{claim.confidence}%</strong></div><p>{claim.summary}</p><small>{claim.age_days} 日前 · {claim.independent ? "独立来源链" : "单一来源链"} · {cn(claim.status)}</small></article>)}
    </section>
    <section className="emergency-panel"><SectionHead eyebrow="潼关专案" title="即时军令" extra={<span>{state.tongguan_status}</span>}/><div className="emergency-orders">{orders.map(({Icon,...order}) => <button key={order.id} onClick={() => onOrder(order.id)} disabled={orderBusy || state.ended}><Icon className="order-icon" aria-hidden="true"/><b>{order.title}</b><small>{order.note}</small><span>利：{order.gain}</span><em>险：{order.risk}</em></button>)}</div>{report&&<article className="field-report"><span>尚书省兵部递报</span><h3>{report.headline}</h3><p>{report.narrative}</p>{report.reasons?.map((reason:string)=><small key={reason}>{reason}</small>)}</article>}{state.ended && <p className="locked-note">潼关篇已结，国家经营与下一章仍可继续。</p>}</section>
  </div></>;
}

function RegionsView({ snap }: { snap: Snapshot }) {
  const [selected, setSelected] = React.useState("changan"); const region = snap.catalog.regions.find(item => item.id === selected); const runtime = snap.management.regions[selected];
  return <div className="split-view"><section><SectionHead eyebrow="山河地理" title="十六地区"/><WorldMap data={snap.catalog} management={snap.management} selected={selected} onSelect={setSelected}/></section><aside className="detail-sheet">
    <SectionHead eyebrow="地区档案" title={region?.name || "选择地区"} extra={region && <Evidence value={region.evidence_status}/>}/>{region && runtime && <><dl><dt>控制者</dt><dd>{cn(region.controller)}</dd><dt>人口区间</dt><dd>{region.population.estimate_range.map((v:number)=>v.toLocaleString()).join(" - ")}</dd><dt>民心</dt><dd>{runtime.support}</dd><dt>动乱</dt><dd>{runtime.unrest}</dd><dt>军压</dt><dd>{region.pressure}</dd><dt>城防</dt><dd>{runtime.fortification}</dd><dt>粮储</dt><dd>{region.grain.stock_glu.toLocaleString()} 粮秣</dd><dt>月赋</dt><dd>{region.tax.cp_per_30_days.toLocaleString()} 财政点</dd></dl><Meter value={runtime.unrest} danger/><p>{cn(region.status)}</p></>}</aside></div>;
}

function CourtView({ snap, onAudience }: { snap: Snapshot; onAudience: (character: any) => void }) {
  const visible = snap.catalog.characters.filter(character => snap.management.characters[character.id]?.status === "active" && !["enemy_only","future_enemy","player_character"].includes(character.audience_status));
  return <section><SectionHead eyebrow="紫宸殿" title="召见与远奏" extra={<span>{visible.length} 人可奏对</span>}/><div className="court-list">{visible.map(character => <button key={character.id} onClick={() => onAudience(character)}><Portrait character={character}/><div><b>{character.name}</b><small>{snap.management.characters[character.id]?.office || character.identity}</small><p>{character.public_stance}</p></div><div className="person-stats"><span>才 {Math.max(character.attributes.administration, character.attributes.military)}</span><span>忠 {character.attributes.loyalty}</span><ChevronRight size={15}/></div></button>)}</div></section>;
}

function ThroneRoom({snap,onAudience,onDecree}:{snap:Snapshot;onAudience:(character:any)=>void;onDecree:(text:string)=>void}){const visible=snap.catalog.characters.filter((character:any)=>snap.management.characters[character.id]?.status==="active"&&!["enemy_only","future_enemy","player_character"].includes(character.audience_status));const recent=Object.entries(snap.conversation.chats||{}).flatMap(([id,messages]:any)=>messages.slice(-2).map((message:any)=>({...message,id}))).sort((a:any,b:any)=>b.turn-a.turn).slice(0,5);return <div className="throne-room"><section className="throne-main"><SectionHead eyebrow="紫宸殿奏对" title="今日召见" extra={<span>{visible.length} 人候旨</span>}/><div className="minister-bench">{visible.slice(0,12).map((character:any)=><button key={character.id} onClick={()=>onAudience(character)}><Portrait character={character}/><b>{character.name}</b><small>{snap.management.characters[character.id]?.office || character.identity}</small><p>{character.public_stance}</p></button>)}</div></section><aside className="court-sidebar"><SectionHead eyebrow="本回合" title="待议军国事"/>{snap.progress.active_event&&<article className="current-matter"><b>{snap.progress.active_event.title}</b><p>{snap.progress.active_event.summary}</p><small>可先召见相关人物，不必立即选择。</small></article>}<SectionHead eyebrow="近来奏对" title="君臣记录"/>{recent.length?recent.map((item:any,index:number)=><article className="recent-chat" key={`${item.id}-${index}`}><b>{snap.catalog.characters.find((c:any)=>c.id===item.id)?.name||"臣下"}</b><p>{item.text}</p><small>{item.scene} · 第{item.turn}回合</small></article>):<p className="empty-note">尚未召见人物。</p>}<SectionHead eyebrow="跨回合" title="密诏与承诺"/><p className="compact-note">密诏 {snap.progress.secret_edicts.length} 道 · 人物关系 {Object.keys(snap.conversation.relationships||{}).length} 组</p></aside></div>}

function StartScreen({slots,onNew,onLoad}:{slots:any[];onNew:()=>void;onLoad:(id:number)=>void}){const auto=slots.find(item=>item.slot_id===0);return <main className="start-screen"><div className="start-backdrop"><div className="era-prologue"><span>天宝十五载 · 公元七五六年</span><h2>渔阳鼙鼓动地来，潼关以东尽为战场</h2><p>安禄山据洛阳称帝，河北郡县反复。哥舒翰统大军扼守潼关，长安朝堂却催战不止。粮道、军令、皇权与民心，都将在数月内决定大唐能否延续。</p><ol><li>稳住潼关军令</li><li>核验前线情报</li><li>保住关中钱粮</li></ol></div><span className="start-seal">唐</span><h1>安史之乱</h1><p>中唐续命</p><small>天宝十五载，潼关军报抵京。你将通过召见、密诏与御笔诏书，重新推动这台失序的国家机器。</small><div className="start-actions">{auto&&<button className="primary" onClick={()=>onLoad(0)}><b>继续游戏</b><span>{auto.year}年{auto.month}月 · 第{auto.turn}回合</span></button>}<button onClick={onNew}><b>开始新游戏</b><span>从潼关危局开始</span></button></div>{slots.filter(item=>item.slot_id!==0).length>0&&<div className="save-list"><h2>载入存档</h2>{slots.filter(item=>item.slot_id!==0).map(slot=><button key={slot.slot_id} onClick={()=>onLoad(slot.slot_id)}><b>{slot.name}</b><span>{slot.year}年{slot.month}月 · 第{slot.turn}回合</span></button>)}</div>}</div></main>}

function DecreeReview({decree,onConfirm,onClose}:{decree:any;onConfirm:(id:number)=>void;onClose:()=>void}){return <div className="drawer-layer" role="dialog" aria-modal="true"><button className="drawer-scrim" onClick={onClose} aria-label="关闭"/><aside className="audience-drawer decree-review"><button className="drawer-close" onClick={onClose}><X size={18}/></button><FilePenLine size={28}/><h2>中书核议</h2><small>{decree.model_used?"文书模型已拟写圣旨":"文书模型未配置，暂保留原始诏意"}</small><blockquote>{decree.rendered_text||decree.text}</blockquote>{decree.decision&&<div className="decree-decision"><b>并入御前裁决</b><span>《{decree.decision.title}》：{decree.decision.choice}</span></div>}<h3>模型拆出的朝堂行动</h3>{decree.candidates.map((item:any,index:number)=><div className="candidate-command" key={index}><b>{directiveMeta[item.kind as DirectiveKind]?.label||"立项核议"}</b><span>投入 {item.amount}</span><small>{item.reason}</small></div>)}{decree.candidates.length?<button className="ask-btn" onClick={()=>onConfirm(decree.id)}>列入本回合行动</button>:<p className="decree-empty">文书模型未返回可执行行动；可直接颁行圣旨与已暂存裁决，或修改诏意后重拟。</p>}<p className="compact-note">行动、御前裁决与诏书将在“颁诏”时统一结算。</p></aside></div>}

const armyActions=[
  {id:"move",label:"调动",note:"沿相邻驿道转移驻地",asset:"movement",Icon:Route},{id:"supply",label:"补给",note:"调拨粮秣，维持远征",asset:"supply",Icon:PackageOpen},{id:"train",label:"整训",note:"整顿军纪，恢复可战兵",asset:"tiger-tally",Icon:Dumbbell},
  {id:"mobilize",label:"征募",note:"补充兵员，增加军费",asset:"recruitment",Icon:UserRoundPlus},{id:"fortify",label:"驻防",note:"加固当前州郡城防",asset:"fortress",Icon:Castle},{id:"investigate",label:"侦察",note:"核验当前最急军情",asset:"scouting",Icon:Binoculars},
] as const;
function FinanceView({ snap }: { snap: Snapshot }) {
  const f = snap.management.finance;
  return <section><SectionHead eyebrow="度支与粮运" title="户部总账" extra={<Wheat size={18}/>}/><div className="finance-summary"><Metric label="可用现银" value={f.cash} unit="财政点"/><Metric label="中央粮储" value={f.grain} unit="粮秣点"/><Metric label="月入" value={f.monthly_income}/><Metric label="月支" value={f.monthly_expenses}/><Metric label="粮食月入" value={f.monthly_grain}/></div><div className="data-table finance-table"><header><span>账户</span><span>类别</span><span>余额</span><span>依据</span></header>{snap.catalog.initial_finance.accounts.map((account:any) => <div key={account.id}><span><b>{account.name}</b></span><span>{cn(account.kind)}</span><span>{account.balance.toLocaleString()}</span><span><Evidence value={snap.catalog.initial_finance.evidence_status}/></span></div>)}</div></section>;
}

function MemorialsView({ snap }: { snap: Snapshot }) {
  const actIndex = Math.max(0, Number(snap.state.act_id?.replace("act", "")) - 1); const act = snap.catalog.acts[actIndex] || snap.catalog.acts[0];
  return <section><SectionHead eyebrow="中书门下" title={`${act.name} · 事件候选`} extra={<Clock3 size={18}/>}/><div className="memorial-list">{act.event_candidates.map((event:any, index:number) => <article key={event.id}><span>{String(index+1).padStart(2,"0")}</span><div><b>{event.name}</b><p>满足对应军情、人物与时间条件后触发</p><small>{event.historical_window==="counterfactual"?"反事实分支":event.historical_window.replace("..","至")}</small></div><Evidence value={event.evidence_status}/></article>)}</div><SectionHead eyebrow="持续事项" title="跨章债务"/>{snap.catalog.ongoing_issues.map((issue:any)=><div className="long-issue" key={issue.id}><div><b>{issue.name}</b><p>{issue.public_summary}</p></div><strong>{issue.pressure}</strong><Evidence value={issue.evidence_status}/></div>)}</section>;
}

function CouncilModal({snap,onClose}:{snap:Snapshot;onClose:()=>void}){const people=snap.catalog.characters.filter((c:any)=>snap.management.characters[c.id]?.status==="active"&&!['enemy_only','future_enemy','player_character'].includes(c.audience_status)).slice(0,14);const [selected,setSelected]=React.useState<string[]>(people.slice(0,3).map((c:any)=>c.id));const [topic,setTopic]=React.useState("潼关应当固守，还是奉诏出击？");const [exchanges,setExchanges]=React.useState<any[]>([]);const [rounds,setRounds]=React.useState<any[]>([]);const [busy,setBusy]=React.useState(false);const [phase,setPhase]=React.useState<"setup"|"done"|"emperor">("setup");const toggle=(id:string)=>setSelected(v=>v.includes(id)?v.filter(x=>x!==id):v.length<6?[...v,id]:v);const runRound=async(roundNo:number,prevMinutes:string,emperorRemark:string)=>{setBusy(true);setPhase("done");setExchanges([]);const body=JSON.stringify({character_ids:selected,topic,round_no:roundNo,previous_minutes:prevMinutes,emperor_remark:emperorRemark});try{const r=await fetch('/api/council/stream',{method:'POST',headers:{'Content-Type':'application/json'},body});if(!r.ok||!r.body)return;const reader=r.body.getReader();const decoder=new TextDecoder();let buf='';while(true){const{done,value}=await reader.read();if(done)break;buf+=decoder.decode(value,{stream:true});const lines=buf.split('\n');buf=lines.pop()||'';for(const line of lines){if(!line.startsWith('data: '))continue;const d=JSON.parse(line.slice(6));if(d.error)break;if(d.done)break;if(d.type==='minutes'){setRounds(prev=>[...prev,{round:d.round,minutes:d.text}]);continue}if(d.type==='emperor_options'){setPhase("emperor");continue}setExchanges(prev=>[...prev,d])}}}catch{}finally{setBusy(false)}};const discuss=()=>runRound(1,"","");const nextRound=(remark:string)=>{const lastMin=rounds.length?rounds[rounds.length-1].minutes:"";runRound(rounds.length+1,lastMin,remark)};if(phase==="setup")return <div className="council-stage"><button className="drawer-scrim" onClick={onClose}/><section className="council-hall"><button className="drawer-close" onClick={onClose}><X size={18}/></button><header><span>紫宸殿集议</span><h2>召集群臣，共议军国</h2><p>选择二至六人入殿。后发言者会听见前臣意见，并依人设与利益作出回应。</p></header><div className="council-seats">{people.map((person:any)=><button key={person.id} className={selected.includes(person.id)?"selected":""} onClick={()=>toggle(person.id)}><Portrait character={person}/><b>{person.name}</b><small>{snap.management.characters[person.id]?.office||person.identity}</small></button>)}</div><div className="council-topic"><textarea value={topic} onChange={e=>setTopic(e.target.value)}/><button onClick={discuss} disabled={busy||selected.length<2}>{busy?'群臣议论中':'开议'}</button></div></section></div>;return <div className="council-stage"><button className="drawer-scrim" onClick={onClose}/><section className="council-hall"><button className="drawer-close" onClick={onClose}><X size={18}/></button><header><span>紫宸殿集议</span><h2>{topic}</h2></header><div className="council-transcript">{rounds.map(r=><div key={r.round} className="council-minutes"><b>{r.round==="final"?"最终纪要":`第${r.round}轮纪要`}</b><p>{r.minutes}</p></div>)}{exchanges.map((item:any,index:number)=><article key={`${item.character_id}-${index}`}><Portrait character={people.find((p:any)=>p.id===item.character_id)}/><div><b>{item.name}</b><small> {item.stance}</small><p>{item.reply}</p></div></article>)}{busy&&<p className="council-busy">群臣议论中…</p>}{phase==="emperor"&&<div className="emperor-panel"><b>陛下圣裁</b><div className="emperor-actions"><button onClick={()=>{const remark=window.prompt("陛下谕旨：");if(remark!==null)nextRound(remark)}}>👑 朕有话说</button><button onClick={()=>setPhase("done")}>📜 查看总结</button><button onClick={onClose}>⚖️ 就此裁决</button><button onClick={()=>nextRound("")}>💬 继续廷议</button></div></div>}</div></section></div>}

function ImperialCourt({snap,onAudience}:{snap:Snapshot;onAudience:(character:any)=>void}){
  const visible=snap.catalog.characters.filter((character:any)=>snap.management.characters[character.id]?.status==="active"&&!['enemy_only','future_enemy','player_character'].includes(character.audience_status)).slice(0,18);
  const left=visible.filter((character:any,index:number)=>character.court_side?character.court_side==="left":index%2===0);
  const right=visible.filter((character:any,index:number)=>character.court_side?character.court_side==="right":index%2===1);
  const recent=Object.entries(snap.conversation.chats||{}).flatMap(([id,messages]:any)=>messages.slice(-1).map((message:any)=>({...message,id}))).sort((a:any,b:any)=>b.turn-a.turn).slice(0,4);
  const group=(character:any)=>character.institution||(['中书','门下','尚书','吏部','户部','礼部','兵部','刑部','工部'].find(name=>character.identity.includes(name))||'朝臣');
  const rank=(characters:any[],side:string)=><div className={`court-rank ${side}`}>{characters.map((character:any)=><button key={character.id} onClick={()=>onAudience(character)}><Portrait character={character}/><span><em>{group(character)}</em><b>{character.name}</b><small>{snap.management.characters[character.id]?.office||character.identity}</small></span></button>)}</div>;
  return <section className="imperial-court"><SectionHead eyebrow="紫宸殿常朝" title="百官奏对" extra={<span>{visible.length} 人在班</span>}/><div className="court-floor">{rank(left,'east')}<div className="throne-axis"><span className="throne-seal">唐</span><small>天子御座</small><h3>{snap.progress.active_event?'军国急务':'今日朝仪'}</h3>{snap.progress.active_event?<article><b>{snap.progress.active_event.title}</b><p>{snap.progress.active_event.summary}</p><em>颁诏推进时须先御前裁断</em></article>:<p>群臣分班候旨，可单独召见，亦可由右上“议”召集多人廷议。</p>}<div><span>中书取旨</span><span>门下审覆</span><span>尚书施行</span></div></div>{rank(right,'west')}</div><footer className="court-notes"><div><b>近来奏对</b>{recent.length?recent.map((item:any)=><p key={`${item.id}-${item.turn}`}><strong>{snap.catalog.characters.find((c:any)=>c.id===item.id)?.name||'臣下'}</strong>{item.text}</p>):<p>尚无奏对记录。</p>}</div><div><b>三省六部</b><p>中书草诏、门下封驳、尚书统六部执行；人物会依机构职责和自身立场参与朝议。</p><small>密诏 {snap.progress.secret_edicts.length} 道 · 君臣关系 {Object.keys(snap.conversation.relationships||{}).length} 组</small></div></footer></section>
}

function HistoryView({ state, resolution }: { state: CoreState; resolution: any }) {
  return <section><SectionHead eyebrow="起居注与露布" title="本局史册" extra={<BookOpen size={18}/>}/>{resolution && <div className="resolution-report"><h3>第 {resolution.turn} 回合结算</h3>{resolution.narration&&<p>{resolution.narration}</p>}{resolution.world_events?.map((event:string,index:number)=><div key={`world-${index}`}><b>天下演化</b><span>{event}</span></div>)}{resolution.reports.map((report:any)=><div key={report.directive_id} className={report.accepted ? "accepted" : "rejected"}><b>{report.headline}</b><span>{report.effects?.join("；") || report.reason}</span></div>)}</div>}<div className="chronicle">{state.history.map((item:string,index:number)=><article key={`${item}-${index}`}><span>{String(state.history.length-index).padStart(3,"0")}</span><p>{item}</p></article>)}</div></section>;
}

function DirectiveDock({ snap, onAdd, onRemove, onResolve, busy }: { snap: Snapshot; onAdd: (draft:any)=>void; onRemove:(id:number)=>void; onResolve:()=>void; busy:boolean }) {
  const [kind, setKind] = React.useState<DirectiveKind>("relief"); const [target,setTarget]=React.useState(""); const [amount,setAmount]=React.useState(10); const [subject,setSubject]=React.useState("");
  const domain = directiveMeta[kind].domain; const options = Object.entries((snap.management as any)[domain] || {}); const actualTarget = target || options[0]?.[0] || "";
  React.useEffect(()=>setTarget(""),[kind]);
  return <section className="directive-dock"><div className="directive-form"><div className="dock-title"><FilePenLine size={18}/><span>拟诏</span></div><select value={kind} onChange={e=>setKind(e.target.value as DirectiveKind)} aria-label="诏令类型">{Object.entries(directiveMeta).map(([id,meta])=><option key={id} value={id}>{meta.label}</option>)}</select><select value={actualTarget} onChange={e=>setTarget(e.target.value)} aria-label="诏令对象">{options.map(([id,value]:any)=><option key={id} value={id}>{value.name || value.title}</option>)}</select><input type="number" min="1" max="100" value={amount} onChange={e=>setAmount(Number(e.target.value))} aria-label="投入规模"/>
    {(kind==="appoint") ? <input value={subject} onChange={e=>setSubject(e.target.value)} placeholder="授予官职"/> : ["investigate","mediate"].includes(kind) ? <select value={subject} onChange={e=>setSubject(e.target.value)} aria-label="承办人"><option value="">不指定承办</option>{Object.entries(snap.management.characters).filter(([,c])=>c.status==="active").map(([id,c])=><option key={id} value={id}>{c.name}</option>)}</select> : null}
    <button onClick={()=>onAdd({kind,target:actualTarget,amount,subject})} disabled={!actualTarget || busy}>加入诏令</button></div><div className="directive-queue"><span>待颁 {snap.management.directives.length}</span>{snap.management.directives.map(item=><div key={item.id}><b>{directiveMeta[item.kind].label}</b><small>{((snap.management as any)[directiveMeta[item.kind].domain]?.[item.target]?.name || (snap.management as any)[directiveMeta[item.kind].domain]?.[item.target]?.title || item.target)} · {item.amount}</small><button onClick={()=>onRemove(item.id)} title="删除诏令" aria-label="删除诏令"><Trash2 size={14}/></button></div>)}</div><button className="resolve-btn" onClick={onResolve} disabled={busy}>{busy ? "正在结算" : snap.management.directives.length ? "颁诏并推进" : "无诏推进一回合"}</button></section>;
}

function AudienceDrawer({ character, office, onClose, onSecret }: { character:any; office?:string; onClose:()=>void; onSecret:(data:any)=>Promise<any> }) {
  const [topic,setTopic]=React.useState("当前最紧要之事是什么？"); const [reply,setReply]=React.useState<any>(null); const [busy,setBusy]=React.useState(false);
  const [scene,setScene]=React.useState(character.audience_status==="remote_only"?"远奏":"朝堂"); const ask=async()=>{setBusy(true); const response=await fetch("/api/audience",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({character_id:character.id,topic,scene})}); setReply(await response.json()); setBusy(false)};
  return <div className={`audience-stage scene-${scene}`} role="dialog" aria-modal="true"><button className="drawer-scrim" onClick={onClose} aria-label="关闭"/><section className="audience-paper"><button className="drawer-close" onClick={onClose} aria-label="关闭"><X size={18}/></button><aside className="audience-figure"><Portrait character={character} large/><h2>{character.name}</h2><small>{office || character.identity}</small><p>{character.public_stance}</p></aside><main className="audience-conversation"><header><b>{scene}奏对</b><div className="scene-switch">{["朝堂","密诏","远奏"].map(value=><button key={value} className={scene===value?"active":""} onClick={()=>setScene(value)}>{value}</button>)}</div></header><div className="dialogue-flow"><div className="player-line">{topic}</div>{reply&&<div className="minister-line"><Portrait character={character}/><p>{reply.accepted?reply.reply:reply.detail}<small>{reply.model_used?"联网人物推演":"规则与中文模板"}</small></p></div>}</div><div className="audience-input"><textarea value={topic} onChange={e=>setTopic(e.target.value)} placeholder="在此问策、下令或试探其心意……"/><button className="ask-btn" onClick={ask} disabled={busy}><MessageSquareText size={16}/>{busy?"候奏中":"发送"}</button>{scene==="密诏"&&<button className="secret-btn" onClick={async()=>{await onSecret({character_id:character.id,text:topic,purpose:"密查"});setReply({accepted:true,reply:"密诏已封缄交付，将跨回合记录进展。",model_used:false})}}>封缄密诏</button>}</div><div className="attribute-grid">{Object.entries(character.attributes).map(([k,v]:any)=><span key={k}>{attributeLabel[k]||"属性"}<b>{v}</b></span>)}</div></main></section></div>;
}

const eventArt:Record<string,string>={shi_assassination:"shi_siming_assassination",shi_siming_assassination:"shi_siming_assassination",heshuo_surrender:"heshuo_surrender",heshuo_settlement:"heshuo_surrender",tibet_threat:"tibet_changan_threat",tibet_changan_threat:"tibet_changan_threat"};
function EventDecision({ event, onChoose, onClose, busy }: { event:any; onChoose:(choice:string)=>void; onClose:()=>void; busy:boolean }){const art=eventArt[event.id];return <section className="event-scroll" aria-label="御前裁断"><button className="drawer-close" onClick={onClose} aria-label="暂不裁断"><X size={18}/></button>{art&&<img className="event-art" src={`/assets/events/${art}.webp`} alt=""/>}<div className="scroll-ribbon">御前裁断</div><div className="event-copy"><span>第 {event.turn} 回合 · 军国奏牍</span><h2>{event.title}</h2><p>{event.summary}</p><blockquote>选择只会暂存为本回合裁决。你仍可召见人物、拟写圣旨；点击“颁诏并裁决”后才会统一结算。</blockquote>{busy&&<p className="decision-busy"><Clock3 aria-hidden="true"/>正在暂存裁决，请稍候…</p>}<div>{event.choices.map((choice:string)=><button key={choice} onClick={()=>onChoose(choice)} disabled={busy}>暂存：{choice}</button>)}</div></div></section>}

function ModelDrawer({ snap,onClose,onSaved }:{snap:Snapshot;onClose:()=>void;onSaved:()=>void}){const [key,setKey]=React.useState("");const [base,setBase]=React.useState("");const [model,setModel]=React.useState("");const [note,setNote]=React.useState("");React.useEffect(()=>{fetch("/api/model-config").then(r=>r.json()).then(data=>{setBase(data.base_url);setModel(data.model)})},[]);const save=async()=>{const r=await fetch("/api/model-config",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({api_key:key,base_url:base,model})});const data=await r.json();setKey("");setNote(data.detail);onSaved()};return <div className="drawer-layer" role="dialog" aria-modal="true"><button className="drawer-scrim" onClick={onClose} aria-label="关闭"/><aside className="audience-drawer model-drawer"><button className="drawer-close" onClick={onClose} aria-label="关闭"><X size={18}/></button><Settings size={28}/><h2>联网模型</h2><p>人物奏对与每回合史官推演使用 OpenAI 兼容接口。规则数值始终由本地确定性结算。</p><label>API 密钥<input type="password" value={key} onChange={e=>setKey(e.target.value)} placeholder={snap.runtime["联网模型"]}/></label><label>接口地址<input value={base} onChange={e=>setBase(e.target.value)}/></label><label>模型名称<input value={model} onChange={e=>setModel(e.target.value)}/></label><button className="ask-btn" onClick={save}>应用当前进程</button>{note&&<blockquote>{note}</blockquote>}</aside></div>}

function EdictComposer({onClose,onSubmit,busy,decision,issued}:{onClose:()=>void;onSubmit:(text:string)=>void;busy:boolean;decision?:any;issued:any[]}){const [parts,setParts]=React.useState<Record<string,string>>({军务:"",内政:"",外事:"",其他:""});const total=Object.values(parts).reduce((sum,text)=>sum+text.length,0);const submit=()=>{const text=Object.entries(parts).filter(([,value])=>value.trim()).map(([kind,value])=>`【${kind}】\n${value.trim()}`).join('\n\n');if(text)onSubmit(text)};return <div className="edict-stage" role="dialog" aria-modal="true"><button className="drawer-scrim" onClick={onClose}/><section className="edict-paper"><button className="drawer-close" onClick={onClose}><X size={18}/></button><header><span>奉天承运皇帝诏曰</span><h2>御笔拟诏</h2><small>中书将用文书模型生成圣旨，并将行动拆为受约束事项</small></header>{decision&&<div className="edict-decision">本回合御前裁决：<b>《{decision.title}》</b> · {decision.choice}</div>}<div className="edict-columns">{Object.keys(parts).map(kind=><label key={kind}><b>{kind[0]}</b><span>{kind}</span><textarea value={parts[kind]} onChange={e=>setParts({...parts,[kind]:e.target.value})} placeholder="写下你的旨意……" maxLength={2000}/><small>{parts[kind].length}/2000</small></label>)}</div><footer><span>本轮诏书 · 共 {total} 字</span><button onClick={submit} disabled={!total||busy}>{busy?"中书核议中":"送中书核议"}</button></footer>{issued.length>0&&<section className="edict-register"><b>本局已颁圣旨</b>{issued.slice(0,3).map(item=><p key={item.id}>第 {item.promulgated_turn||item.turn} 回合 · {item.rendered_text||item.text}</p>)}</section>}</section></div>}

const modelRoles={chat:{name:"人物议政",note:"人物扮演、朝堂争论、密诏与远奏"},simulation:{name:"回合推演",note:"长上下文、多因素分析与结算叙事"},utility:{name:"文书与记忆",note:"诏书润色、奏折生成、摘要与长期记忆"}};
function MultiModelDrawer({onClose,onSaved}:{snap:Snapshot;onClose:()=>void;onSaved:()=>void}){const [configs,setConfigs]=React.useState<any>({});const [active,setActive]=React.useState("chat");const [form,setForm]=React.useState({api_key:"",base_url:"",model:""});const [note,setNote]=React.useState("");React.useEffect(()=>{fetch("/api/model-config").then(r=>r.json()).then(data=>setConfigs(data.roles||{}))},[]);React.useEffect(()=>{const cfg=configs[active]||{};setForm({api_key:"",base_url:cfg.base_url||"",model:cfg.model||""})},[active,configs]);const save=async()=>{const r=await fetch("/api/model-config",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({...form,role:active})});const data=await r.json();setNote(data.detail||"");if(!r.ok)return;setConfigs((current:any)=>({...current,[active]:{...current[active],configured:data.configured,base_url:data.base_url||form.base_url,model:data.model||form.model}}));setForm({...form,api_key:""});onSaved()};return <div className="drawer-layer model-center" role="dialog"><button className="drawer-scrim" onClick={onClose}/><section className="model-console"><button className="drawer-close" onClick={onClose}><X size={18}/></button><header><span>模型分工</span><h2>三司推演配置</h2><p>每项可使用不同供应商、接口和模型；密钥仅保存在当前后端进程。</p></header><nav>{Object.entries(modelRoles).map(([id,item])=><button className={active===id?"active":""} key={id} onClick={()=>setActive(id)}><b>{item.name}</b><small>{item.note}</small><em>{configs[id]?.configured?configs[id].model||"已配置":"使用通用回退"}</em></button>)}</nav><main><label>接口地址<input value={form.base_url} onChange={e=>setForm({...form,base_url:e.target.value})}/></label><label>模型名称<input value={form.model} onChange={e=>setForm({...form,model:e.target.value})}/></label><label>API 密钥<input type="password" value={form.api_key} onChange={e=>setForm({...form,api_key:e.target.value})} placeholder="留空则沿用当前密钥"/></label><button className="ask-btn" onClick={save}>应用此职责配置</button>{note&&<blockquote>{note}</blockquote>}</main></section></div>}

function ArmyCommandView({snap,onMove,onDirective}:{snap:Snapshot;onMove:(army:string,destination:string)=>void;onDirective:(draft:any)=>void}){const activeAct=Number(snap.state.act_id?.replace("act",""))||1;const routes:Record<string,string[]>={changan:["tongguan","mawei"],mawei:["changan","jiannan"],tongguan:["changan","lingbao"],lingbao:["tongguan","shanjun"],shanjun:["lingbao","luoyang"],luoyang:["shanjun","hedong","suiyang"],hedong:["luoyang","fanyang","shuofang"],fanyang:["hedong","changshan"],changshan:["fanyang","pingyuan"],pingyuan:["changshan","suiyang"],shuofang:["hedong","hexi"],hexi:["shuofang","longyou"],longyou:["hexi","jiannan"],jiannan:["longyou","mawei"],suiyang:["pingyuan","luoyang","yangzhou"],yangzhou:["suiyang"]};const available=snap.catalog.armies.filter((item:any)=>item.act_from<=activeAct&&item.power.startsWith("tang"));const [selected,setSelected]=React.useState(available[0]?.id||"");const army=snap.catalog.armies.find((item:any)=>item.id===selected);const field=snap.strategy.armies?.[selected];const live=snap.management.armies[selected];const region=field?.region||live?.region||army?.region||"";const [destinationChoice,setDestinationChoice]=React.useState(routes[region]?.[0]||"");React.useEffect(()=>setDestinationChoice(routes[region]?.[0]||""),[region]);const regionName=snap.catalog.regions.find((item:any)=>item.id===region)?.name||region;const issue=Object.entries(snap.management.issues).sort((a:any,b:any)=>b[1].tension-a[1].tension)[0]?.[0];const command=(id:string)=>{if(!army)return;if(id==="move"){if(destinationChoice)onMove(army.id,destinationChoice);return}const draft=id==="fortify"?{kind:"fortify",target:region,amount:10,subject:army.name+"驻防"}:id==="investigate"?{kind:"investigate",target:issue,amount:10,subject:army.name+"斥候"}:id==="train"?{kind:"supply",target:army.id,amount:8,subject:army.name+"整训"}:{kind:id,target:army.id,amount:10,subject:army.name};onDirective(draft)};return <section className="army-command"><SectionHead eyebrow="天下兵马" title="军令台" extra={<span>军令先入队，回合推进时统一执行</span>}/><div className="army-command-grid"><div className="army-map"><CampaignMap data={snap.catalog} management={snap.management} strategy={snap.strategy} selected={region}/><div className="army-tabs">{available.map((item:any)=><button className={selected===item.id?"active":""} key={item.id} onClick={()=>setSelected(item.id)}>{item.name}</button>)}</div></div><article className="army-dossier"><span>兵部鱼袋 · 在册军伍</span><h2>{army?.name||"未选军队"}</h2><p>{snap.catalog.characters.find((item:any)=>item.id===army?.commander)?.name||"统帅待定"} 统领 · 驻 {regionName}</p><label className="army-route-select">预定调往<select value={destinationChoice} onChange={event=>setDestinationChoice(event.target.value)} disabled={!routes[region]?.length}><option value="">选择相邻目的地</option>{(routes[region]||[]).map(id=><option value={id} key={id}>{snap.catalog.regions.find((item:any)=>item.id===id)?.name||id}</option>)}</select></label><dl><dt>在队</dt><dd>{Number(field?.strength??live?.strength??0).toLocaleString()}</dd><dt>可战</dt><dd>{Number(live?.fit_strength??army?.fit_strength??0).toLocaleString()}</dd><dt>补给</dt><dd>{field?.supply??live?.supply??0}</dd><dt>士气</dt><dd>{field?.morale??live?.morale??0}</dd></dl><Meter value={field?.supply??live?.supply??0}/><small>调动只登记目的地，不会立即改变驻地；推进回合时由行军规则和推演模型共同写入战报。</small></article><div className="army-action-grid">{armyActions.map(({Icon,...action})=><button key={action.id} onClick={()=>command(action.id)} disabled={!army||(action.id==="move"&&!destinationChoice)} style={{backgroundImage:"linear-gradient(#1517132b,#151713e8),url('/assets/ui/army-actions/"+action.asset+".webp')"}}><Icon className="army-action-icon" aria-hidden="true"/><b>{action.label}</b><span>{action.note}</span></button>)}</div></div>{(snap.strategy.pending_movements?.length||snap.management.directives.length)>0&&<div className="army-queue"><b>本回合待执行</b>{(snap.strategy.pending_movements||[]).map((item:any)=><span key={item.army_id}>调动 · {snap.catalog.armies.find((army:any)=>army.id===item.army_id)?.name||item.army_id} → {snap.catalog.regions.find((region:any)=>region.id===item.destination)?.name||item.destination}</span>)}{snap.management.directives.map(item=><span key={item.id}>{item.subject?.includes("整训")?"整训整备":directiveMeta[item.kind]?.label||item.kind} · {item.subject||item.target} · 投入 {item.amount}</span>)}</div>}{snap.strategy.battle_log?.length>0&&<div className="battle-log"><h3>近期战报</h3>{snap.strategy.battle_log.slice(0,5).map((item:string,index:number)=><p key={index}>{item}</p>)}</div>}</section>}

function ReportCenter({snap}:{snap:Snapshot}){const [filter,setFilter]=React.useState("全部");const reports=[...snap.agent_runs.map((item:any)=>({kind:item.kind.includes("推演")?"推演":item.kind.includes("奏对")?"奏对":"模型",title:item.kind,body:item.detail||item.model+" · "+(item.succeeded?"已完成":"已回退"),meta:item.created_at})),...snap.strategy.battle_log.slice(0,8).map((item:string)=>({kind:"军报",title:"战场动态",body:item,meta:"本回合"})),...(snap.progress.active_event?[{kind:"事件",title:snap.progress.active_event.title,body:snap.progress.active_event.summary,meta:"待裁决"}]:[])];const visible=filter==="全部"?reports:reports.filter(item=>item.kind===filter);return <section className="report-center"><SectionHead eyebrow="中书门下 · 兵部" title="奏报中心" extra={<span>{reports.length} 条记录</span>}/><div className="report-filters">{["全部","军报","推演","奏对","事件"].map(item=><button key={item} className={filter===item?"active":""} onClick={()=>setFilter(item)}>{item}</button>)}</div><div className="report-layout"><div className="report-feed">{visible.length?visible.map((item:any,index:number)=><article className={"report-card report-"+item.kind} key={item.title+"-"+index}><header><b>{item.title}</b><small>{item.kind} · {item.meta}</small></header><p>{item.body}</p></article>):<p className="empty-note">此类奏报尚未形成。</p>}</div><aside className="report-side"><SectionHead eyebrow="当前事件" title="待裁事项"/>{snap.progress.active_event?<article className="current-matter"><b>{snap.progress.active_event.title}</b><p>{snap.progress.active_event.summary}</p><small>推进回合前可召对、拟诏，裁决会与军令统一结算。</small></article>:<p className="empty-note">当前没有待裁事件。</p>}<SectionHead eyebrow="持续事项" title="跨章债务"/>{snap.catalog.ongoing_issues.slice(0,5).map((issue:any)=><div className="report-debt" key={issue.id}><b>{issue.name}</b><strong>{issue.pressure}</strong><Meter value={issue.pressure} danger/></div>)}</aside></div></section>}

const policyEffects:Record<string,string>={unify_command:"军令局势 +10；朝堂冲突下降",repair_post_roads:"军令局势 +6；传令更稳定",restrain_eunuchs:"军令局势 +8；皇威承压后回升",reinforce_tongguan:"城防 +8；驻军士气 +3",shuofang_recruit:"朔方增兵约 6,000；消耗现银",contact_resistance:"河朔人心 +12；民心略升",divide_yan:"河朔人心 +16；叛军内部分裂",secure_grain_route:"月粮 +15；月入 +8",relieve_guanzhong:"粮储 -80；各地民心上升"};
function PolicyFocusViewRich({snap,onSelect}:{snap:Snapshot;onSelect:(id:string)=>void}){const completed=new Set<string>(snap.progress.completed_policies||[]);const active=snap.progress.active_policy;return <section className="policy-view"><SectionHead eyebrow="经国远图" title="国策树" extra={<span>每回合至多推进一项</span>}/><p className="policy-intro">选择一个可用节点。国策在本回合推进时完成，并写入帝国修正；前置节点和资源不足会阻止施行。</p><div className="policy-tree">{focusBranches.map(branch=><div className={"policy-branch "+branch.tone} key={branch.name}><h3>{branch.name}</h3><div>{branch.nodes.map(node=>{const done=completed.has(node.id);const available=!done&&!active&&node.requires.every(req=>completed.has(req));return <button className={"policy-node "+(done?"unlocked":available?"available":"locked")} key={node.id} disabled={!available} title={policyEffects[node.id]} onClick={()=>onSelect(node.id)}><span>{done?<CheckCircle2/>:available?<CirclePlay/>:<LockKeyhole/>}</span><b>{node.title}</b><small>{done?"帝国修正已生效":policyEffects[node.id]||"需要前置国策"}</small></button>})}</div></div>)}</div></section>}

const focusBranches=[
  {name:"中枢整饬",tone:"civil",nodes:[{id:"unify_command",title:"整饬军令体系",requires:[]},{id:"repair_post_roads",title:"重建驿传",requires:[]},{id:"restrain_eunuchs",title:"裁抑近习干政",requires:["unify_command"]}]},
  {name:"军镇经略",tone:"war",nodes:[{id:"reinforce_tongguan",title:"加强潼关防务",requires:[]},{id:"shuofang_recruit",title:"朔方整军募骑",requires:["reinforce_tongguan"]}]},
  {name:"河朔联络",tone:"frontier",nodes:[{id:"contact_resistance",title:"联络河北义军",requires:[]},{id:"divide_yan",title:"离间燕廷诸将",requires:["contact_resistance"]}]},
  {name:"财赋民生",tone:"people",nodes:[{id:"secure_grain_route",title:"保全江淮漕运",requires:[]},{id:"relieve_guanzhong",title:"关中军民赈济",requires:["secure_grain_route"]}]},
];
function App(){
  const [snap,setSnap]=React.useState<Snapshot|null>(null); const [entered,setEntered]=React.useState(false); const [tab,setTab]=React.useState<Tab>("court"); const [busy,setBusy]=React.useState(false); const [error,setError]=React.useState(""); const [audience,setAudience]=React.useState<any>(null); const [decree,setDecree]=React.useState<any>(null); const [modelOpen,setModelOpen]=React.useState(false); const [councilOpen,setCouncilOpen]=React.useState(false); const [edictOpen,setEdictOpen]=React.useState(false); const [eventOpen,setEventOpen]=React.useState(false); const [resolution,setResolution]=React.useState<any>(null); const [orderReport,setOrderReport]=React.useState<any>(null);
  const load=React.useCallback(async()=>{const r=await fetch("/api/snapshot"); if(!r.ok) throw new Error("局势载入失败"); setSnap(await r.json())},[]);
  React.useEffect(()=>{load().catch(e=>setError(e.message))},[load]);
  const act=async(fn:()=>Promise<Response>)=>{setBusy(true);setError("");try{const r=await fn();const data=await r.json();if(!r.ok)throw new Error(data.detail||"操作失败");await load();return data}catch(e){setError(e instanceof Error?e.message:"操作失败")}finally{setBusy(false)}};
  const order=async(value:Order)=>{const data=await act(()=>fetch("/api/turn",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({order:value})}));if(data)setOrderReport(data)};
  const add=(draft:any)=>act(()=>fetch("/api/directives",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(draft)}));
  const remove=(id:number)=>act(()=>fetch(`/api/directives/${id}`,{method:"DELETE"}));
  const resolve=async()=>{const data=await act(()=>fetch("/api/resolve",{method:"POST",headers:{"Content-Type":"application/json"},body:"{}"}));if(data?.requires_choice){setEventOpen(true);return}if(data?.accepted===false){setError(data.detail||"裁决暂不能颁行");return}if(data){setEventOpen(false);setResolution({...data.result,narration:data.narration,campaign:data.campaign_result});setTab("history")}}; const queueEventChoice=async(choice:string)=>{const data=await act(()=>fetch("/api/events/choice",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({choice})}));if(data?.accepted)setEventOpen(false);else if(data?.detail)setError(data.detail)}; const advanceTurn=()=>snap?.progress.active_event&&!snap.progress.pending_event_choice?setEventOpen(true):resolve();
  const secret=(draft:any)=>act(()=>fetch("/api/secret-edicts",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(draft)}));
  const freeform=async(text:string)=>{const data=await act(()=>fetch("/api/decrees/freeform",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({text})}));if(data){setDecree(data.decree);setEdictOpen(false)}};
  const confirmDecree=async(id:number)=>{const data=await act(()=>fetch(`/api/decrees/${id}/confirm`,{method:"POST"}));if(data?.accepted)setDecree(null);else if(data?.detail)setError(data.detail)};
  const reset=async()=>{await act(()=>fetch("/api/reset",{method:"POST"}));setResolution(null);setTab("court");setEntered(true)};
  const loadSlot=async(id:number)=>{await act(()=>fetch(`/api/saves/${id}/load`,{method:"POST"}));setEntered(true);setTab("court")};
  const saveSlot=async()=>{const name=window.prompt("请输入存档名称",`第${snap?.progress.total_turn||1}回合存档`);if(name)await act(()=>fetch("/api/saves",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({slot_id:Date.now()%1000000,name})}))};
  const moveArmy=(army_id:string,destination:string)=>act(()=>fetch("/api/armies/move",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({army_id,destination})}));
  const selectPolicy=async(policy_id:string)=>{const data=await act(()=>fetch("/api/policies/select",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({policy_id})}));if(data?.accepted===false)setError(data.detail||"国策暂不可用")};
  const ArmyView=ArmyCommandView;const MemorialsView=ReportCenter;const PolicyView=({snap}:{snap:Snapshot})=><PolicyFocusViewRich snap={snap} onSelect={selectPolicy}/>;
  if(!snap)return <main className="loading">正在展开天下图册...</main>;
  if(!entered)return <StartScreen slots={snap.save_slots||[]} onNew={reset} onLoad={loadSlot}/>;
  const s=snap.state,m=snap.management,pendingDecision=snap.progress.pending_event_choice;
  const TurnActionIcon=snap.progress.active_event&&!pendingDecision?Gavel:m.directives.length||pendingDecision?Stamp:CirclePlay;
  const roleConfigs=snap.runtime["模型职责"]||{};const configuredRoles=Object.entries(roleConfigs).filter(([,config]:any)=>config.configured);const modelSummary=configuredRoles.map(([id,config]:any)=>`${id==="chat"?"人物":id==="simulation"?"推演":"文书"}：${config.model||"已配置"}`).join(" / ")||"使用中文模板";
  return <main className="game-shell"><header className="topbar"><div className="brand"><span className="seal">唐</span><div><h1>安史之乱</h1><p>中唐续命 · 国家军政中枢</p></div></div><div className="top-metrics"><Metric label="皇威" value={s.central_prestige}/><Metric label="军势" value={s.military_power}/><Metric label="民心" value={s.popular_support}/><Metric label="现银" value={m.finance.cash}/><Metric label="粮储" value={m.finance.grain}/></div><div className="date-block"><span>{s.phase} · 第 {snap.progress.total_turn} 回合 · {snap.progress.year}年{snap.progress.month}月</span><button className="model-status" onClick={()=>setModelOpen(true)} title={modelSummary}><Settings aria-hidden="true"/><span><b>模型 {configuredRoles.length}/3</b><small>{modelSummary}</small></span></button></div><div className="header-actions"><button onClick={()=>setCouncilOpen(true)} title="召集群议" aria-label="召集群议"><MessagesSquare/></button><button onClick={saveSlot} title="另存游戏" aria-label="另存游戏"><Save/></button><button onClick={()=>setEntered(false)} title="返回主菜单" aria-label="返回主菜单"><LogOut/></button><button onClick={reset} title="重新开始" aria-label="重新开始"><RotateCcw/></button></div></header>
    <div className="campaign-rail">{snap.acts.map((a:any,i:number)=><div key={a.id} className={a.id===s.act_id?"current":""}><span>0{i+1}</span><b>{a.title}</b><small>{a.date_range}</small></div>)}</div>
    <div className="game-body"><nav className="side-nav">{nav.map(({id,label,Icon})=><button key={id} className={tab===id?"active":""} onClick={()=>setTab(id)} title={label}><Icon size={18}/><span>{label}</span>{id==="memorials"&&<b>{Object.values(m.issues).filter(i=>i.tension>=70).length}</b>}</button>)}</nav><div className="main-workspace">{tab==="court"&&<ImperialCourt snap={snap} onAudience={setAudience}/>} {tab==="overview"&&<Overview snap={snap} onOrder={order} orderBusy={busy} report={orderReport}/>} {tab==="map"&&<RegionsView snap={snap}/>} {tab==="army"&&<ArmyView snap={snap} onMove={moveArmy} onDirective={add}/>} {tab==="memorials"&&<MemorialsView snap={snap}/>} {tab==="policy"&&<PolicyView snap={snap}/>} {tab==="history"&&<HistoryView state={s} resolution={resolution}/>}</div></div>
    {error&&<div className="toast-error"><AlertTriangle size={16}/>{error}</div>}<button className="edict-launch" onClick={()=>setEdictOpen(true)} title="拟写诏书" aria-label="拟写诏书"><ScrollText aria-hidden="true"/><small>拟诏</small></button><button className="turn-advance" onClick={advanceTurn} disabled={busy} title={snap.progress.active_event&&!pendingDecision?"御前裁决":m.directives.length||pendingDecision?"颁诏并推进":"推进回合"}><TurnActionIcon aria-hidden="true"/><small>{snap.progress.active_event&&!pendingDecision?"御前裁决":m.directives.length||pendingDecision?`颁诏${pendingDecision?"并裁决":""}`:"推进回合"}</small></button>{eventOpen&&snap.progress.active_event&&<div className="event-overlay"><EventDecision event={snap.progress.active_event} onChoose={queueEventChoice} onClose={()=>setEventOpen(false)} busy={busy}/></div>}{edictOpen&&<EdictComposer onClose={()=>setEdictOpen(false)} onSubmit={freeform} busy={busy} decision={pendingDecision} issued={(snap.conversation.freeform_decrees||[]).filter((item:any)=>item.status==="已颁行")}/>} {audience&&<AudienceDrawer character={audience} office={snap.management.characters[audience.id]?.office} onClose={()=>setAudience(null)} onSecret={secret}/>} {decree&&<DecreeReview decree={decree} onConfirm={confirmDecree} onClose={()=>setDecree(null)}/>} {councilOpen&&<CouncilModal snap={snap} onClose={()=>setCouncilOpen(false)}/>} {modelOpen&&<MultiModelDrawer snap={snap} onClose={()=>setModelOpen(false)} onSaved={load}/>}</main>;
}

createRoot(document.getElementById("root")!).render(<React.StrictMode><App/></React.StrictMode>);
